const body = $input.first().json.body || $input.first().json;
const { niche, city, project_id, target_url, competitors, batch_size, mode, 
        niche_cluster, priority_engines } = body;

if (!niche) throw new Error('Поле "niche" обязательно');
if (!city) throw new Error('Поле "city" обязательно');
if (!project_id) throw new Error('Поле "project_id" обязательно');

let competitorsList = [];
if (Array.isArray(competitors) && competitors.length > 0) {
  competitorsList = competitors
    .filter(c => typeof c === 'string' && c.startsWith('http'))
    .slice(0, 10);
}

const runMode = mode || 'full';

return [{ json: {
  niche, city, project_id,
  niche_cluster: niche_cluster || 'commercial_local',
  priority_engines: priority_engines || 'both',
  target_url: target_url || '',
  competitors: competitorsList,
  batch_size: Math.min(batch_size || 3, 5),
  mode: runMode,
  embed_query: niche + ' ' + city + ' структура страницы лендинг блоки секции конверсия SEO 2026',
  started_at: new Date().toISOString(),
  workflow_version: 'v4.0_pro'
}}];

let structResults = [];
let personaResults = [];

try { structResults = $('RAG Structures').first().json.result || []; } catch(e) {}
try { personaResults = $('RAG Personas').first().json.result || []; } catch(e) {}

let context = '';
if (structResults.length > 0) {
  context = '=== СТРУКТУРЫ СТРАНИЦ ПОХОЖИХ НИШ (RAG) ===\n\n';
  structResults.forEach((r, i) => {
    const p = r.payload || {};
    context += `Проект ${i+1} (сходство: ${Math.round(r.score*100)}%):\n`;
    context += `  Ниша: ${p.niche||''}, город: ${p.city||''}\n`;
    if (p.blocks_structure || p.structure_summary) {
      const summary = p.blocks_structure || p.structure_summary;
      const text = typeof summary === 'string' ? summary : JSON.stringify(summary);
      context += `  Блоки: ${text.substring(0, 800)}\n`;
    }
    context += '---\n';
  });
}

if (personaResults.length > 0) {
  context += '\n=== ПЕРСОНЫ ЦА (RAG) ===\n\n';
  personaResults.forEach((r, i) => {
    const p = r.payload || {};
    context += `Персона ${i+1}: ${p.persona_name || ''}\n`;
    context += `  JTBD: ${p.main_jtbd || ''}\n`;
    context += `  Боли: ${p.problems_summary || ''}\n---\n`;
  });
}

return [{ json: {
  rag_context: context || 'Нет данных из RAG — первый проект.',
  rag_struct_count: structResults.length,
  rag_persona_count: personaResults.length,
  rag_avg_score: structResults.length > 0 
    ? Math.round(structResults.reduce((s,r) => s + (r.score||0), 0) / structResults.length * 100) / 100 
    : 0
}}];

// Auth handled via headers on each NocoDB node
const validate = $('Validate Input').first().json;
return [{ json: { ...validate, auth_method: 'header' } }];

const response = $input.first().json;
const validate = $('Validate Input').first().json;
const ragInfo = $('Format RAG Context').first().json;

const rows = response.list || (Array.isArray(response) ? response : []);
if (rows.length === 0) {
  throw new Error('Нет кластеров для project_id: ' + validate.project_id + '. Сначала запустите NN_01.');
}

const clusters = rows.map(r => {
  let keywords = [];
  try { keywords = typeof r.keywords === 'string' ? JSON.parse(r.keywords) : (r.keywords || []); } catch(e) {}
  return {
    cluster_name: r.cluster_name || r.Title || '',
    main_keyword: r.main_keyword || '',
    page_type: r.page_type || 'commercial',
    priority: r.priority || 99,
    keywords_count: r.keywords_count || keywords.length,
    total_frequency: r.total_frequency || 0,
    recommended_url: r.recommended_url || '',
    aeo_query: r.aeo_query || '',
    top_keywords: (keywords.slice(0, 10)).map(k => typeof k === 'string' ? k : (k.keyword || k.text || '')).join(', ')
  };
}).filter(c => c.cluster_name);

// Collect all URLs for internal linking validation
const allUrls = clusters.map(c => ({ cluster: c.cluster_name, url: c.recommended_url }));

const BATCH_SIZE = validate.batch_size || 3;
const batches = [];
for (let i = 0; i < clusters.length; i += BATCH_SIZE) {
  const batch = clusters.slice(i, i + BATCH_SIZE);
  batches.push({
    batch_index: Math.floor(i / BATCH_SIZE) + 1,
    total_batches: Math.ceil(clusters.length / BATCH_SIZE),
    batch_clusters: batch,
    clusters_summary: batch.map((c, j) =>
      (i + j + 1) + '. [' + c.page_type.toUpperCase() + '] ' + c.cluster_name +
      ' | Ключ: ' + c.main_keyword +
      ' | Частота: ' + c.total_frequency +
      ' | URL: ' + c.recommended_url +
      (c.aeo_query ? ' | AEO: ' + c.aeo_query : '') +
      (c.top_keywords ? ' | Ключи: ' + c.top_keywords : '')
    ).join('\n'),
    batch_size: batch.length,
    niche: validate.niche,
    city: validate.city,
    project_id: validate.project_id,
    target_url: validate.target_url,
    competitors: validate.competitors,
    total_clusters: clusters.length,
    all_project_urls: JSON.stringify(allUrls),
    rag_context: ragInfo.rag_context
  });
}

return batches.map(b => ({ json: b }));

const groqResponse = $input.first().json;
const batchInfo = $('Build Batch Prompt').first().json;

// Error handling
if (groqResponse.error) {
  return [{ json: {
    batch_index: batchInfo.batch_index,
    structures: [],
    nocodb_rows: [],
    error: groqResponse.error.message || 'Groq API error',
    groq_tokens: 0,
    total_batches: batchInfo.total_batches,
    structures_count: 0,
    status: 'error'
  }}];
}

const rawContent = groqResponse?.choices?.[0]?.message?.content || '';
let cleanJson = rawContent.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();

let parsed;
try {
  parsed = JSON.parse(cleanJson);
} catch (err) {
  // Fallback: extract JSON
  try {
    const objMatch = cleanJson.match(/\{[\s\S]+\}/);
    if (objMatch) parsed = JSON.parse(objMatch[0]);
  } catch(e2) {}
  if (!parsed) {
    try {
      const arrMatch = cleanJson.match(/\[[\s\S]+\]/);
      if (arrMatch) parsed = { page_structures: JSON.parse(arrMatch[0]) };
    } catch(e3) {}
  }
  if (!parsed) {
    return [{ json: {
      batch_index: batchInfo.batch_index, structures: [], nocodb_rows: [],
      error: 'JSON parse failed. Raw (first 500): ' + rawContent.substring(0, 500),
      groq_tokens: groqResponse?.usage?.total_tokens || 0,
      total_batches: batchInfo.total_batches, structures_count: 0, status: 'parse_error'
    }}];
  }
}

// Normalize
if (Array.isArray(parsed)) parsed = { page_structures: parsed };
else if (parsed && !parsed.page_structures) {
  if (parsed.cluster_name || parsed.blocks) parsed = { page_structures: [parsed] };
}

// Valid project URLs for link validation
let validUrls = [];
try { validUrls = JSON.parse(batchInfo.all_project_urls || '[]'); } catch(e) {}
const validUrlSet = new Set(validUrls.map(u => u.url));

// Process & validate each structure
const warnings = [];
const structures = (parsed.page_structures || []).map((s, idx) => {
  const blocks = Array.isArray(s.blocks) ? s.blocks.map((b, bi) => ({
    order: b.order || (bi+1),
    block_name: b.block_name || 'Block '+(bi+1),
    block_type: b.block_type || 'content',
    h2: b.h2 || '',
    content_guidelines: b.content_guidelines || '',
    word_count: b.word_count || 100,
    keywords_to_include: Array.isArray(b.keywords_to_include) ? b.keywords_to_include : [],
    schema_type: b.schema_type || null,
    conversion_element: b.conversion_element || null,
    is_above_fold: !!b.is_above_fold,
    design_notes: b.design_notes || '',
    engine_relevance: b.engine_relevance || 'both'
  })) : [];

  // Validation warnings
  if (blocks.length < 8) warnings.push(s.cluster_name + ': только ' + blocks.length + ' блоков (нужно ≥8)');

  const meta = s.meta || {};
  if (meta.title_template && meta.title_template.length > 65) warnings.push(s.cluster_name + ': Title ' + meta.title_template.length + ' символов (макс 60)');
  if (meta.description_template && meta.description_template.length > 165) warnings.push(s.cluster_name + ': Description ' + meta.description_template.length + ' символов (макс 155)');

  const aeo = s.aeo_block || {};
  if (!aeo.question) warnings.push(s.cluster_name + ': отсутствует AEO question');

  // Validate internal links against real URLs
  const links = Array.isArray(s.internal_links) ? s.internal_links.filter(l => {
    if (l.target_url && !validUrlSet.has(l.target_url)) {
      warnings.push(s.cluster_name + ': ссылка на несуществующий URL ' + l.target_url);
      return false;
    }
    return true;
  }) : [];

  const totalWords = s.total_word_count || blocks.reduce((sum, b) => sum + (b.word_count || 0), 0);

  return {
    cluster_name: s.cluster_name || 'Structure '+(idx+1),
    main_keyword: s.main_keyword || '',
    page_type: ['commercial','informational','navigation','local'].includes(s.page_type) ? s.page_type : 'commercial',
    recommended_url: s.recommended_url || '',
    meta: {
      title_template: meta.title_template || '',
      description_template: meta.description_template || '',
      h1_template: meta.h1_template || '',
      og_title: meta.og_title || meta.title_template || '',
      og_description: meta.og_description || meta.description_template || ''
    },
    blocks,
    total_word_count: totalWords,
    total_blocks: blocks.length,
    internal_links: links,
    aeo_block: {
      question: aeo.question || '',
      short_answer: aeo.short_answer || '',
      detailed_answer: aeo.detailed_answer || '',
      related_questions: Array.isArray(aeo.related_questions) ? aeo.related_questions : []
    },
    schema_types: Array.isArray(s.schema_types) ? s.schema_types : [],
    priority_score: s.priority_score || 50,
    estimated_conversion_elements: s.estimated_conversion_elements || blocks.filter(b => b.conversion_element).length,
    geo_block: s.geo_block || { citable_facts: [], expert_quotes: [], data_points: [] },
    content_quality_layers: s.content_quality_layers || {}
  };
});

// Build NocoDB rows
const nocodbRows = structures.map(s => ({
  project_id: batchInfo.project_id,
  niche: batchInfo.niche,
  city: batchInfo.city,
  cluster_name: s.cluster_name,
  main_keyword: s.main_keyword,
  page_type: s.page_type,
  recommended_url: s.recommended_url,
  title_template: s.meta.title_template,
  description_template: s.meta.description_template,
  h1_template: s.meta.h1_template,
  og_title: s.meta.og_title,
  og_description: s.meta.og_description,
  blocks: JSON.stringify(s.blocks),
  total_blocks: s.total_blocks,
  total_word_count: s.total_word_count,
  internal_links: JSON.stringify(s.internal_links),
  aeo_question: s.aeo_block.question,
  aeo_short_answer: s.aeo_block.short_answer,
  aeo_detailed_answer: s.aeo_block.detailed_answer,
  aeo_related_questions: JSON.stringify(s.aeo_block.related_questions),
  schema_types: JSON.stringify(s.schema_types),
  priority_score: s.priority_score,
  conversion_elements_count: s.estimated_conversion_elements,
  geo_citable_facts: JSON.stringify((s.geo_block || {}).citable_facts || []),
  content_quality: JSON.stringify(s.content_quality_layers || {}),
  status: 'active',
  version: 'v4.0',
  batch_index: batchInfo.batch_index,
  created_at: new Date().toISOString()
}));

return [{ json: {
  batch_index: batchInfo.batch_index,
  total_batches: batchInfo.total_batches,
  structures_count: structures.length,
  nocodb_rows: nocodbRows,
  groq_tokens: groqResponse?.usage?.total_tokens || 0,
  warnings: warnings,
  error: null,
  status: 'ok'
}}];

const batch = $('Parse & Validate Batch').first().json;
const saveResult = $input.first().json;

const logEntry = {
  step: '04_page_structure',
  batch: batch.batch_index + '/' + batch.total_batches,
  structures: batch.structures_count,
  tokens: batch.groq_tokens,
  warnings: batch.warnings?.length || 0,
  saved: !saveResult.error,
  status: batch.error ? 'ERROR: ' + batch.error : 'OK',
  timestamp: new Date().toISOString()
};

console.log('[NN_04] ' + JSON.stringify(logEntry));
return [{ json: logEntry }];

// Adaptive delay: check remaining rate limit from Groq headers
// Default 3s pause between batches, increase if approaching limit
const batch = $('Parse & Validate Batch').first().json;
const delay = batch.groq_tokens > 6000 ? 5000 : 2000;
await new Promise(resolve => setTimeout(resolve, delay));
return [{ json: { delayed_ms: delay } }];

const response = $input.first().json;
const validate = $('Validate Input').first().json;
const rows = response.list || [];

const typeBreakdown = {};
rows.forEach(r => { typeBreakdown[r.page_type || 'unknown'] = (typeBreakdown[r.page_type || 'unknown'] || 0) + 1; });

const topStructures = rows
  .sort((a, b) => (b.priority_score || 0) - (a.priority_score || 0))
  .slice(0, 15)
  .map(r => r.cluster_name + ' [' + r.page_type + ']: ' + r.total_blocks + ' блоков, ' + r.total_word_count + ' слов, score=' + r.priority_score)
  .join('\n');

const aeoSummary = rows
  .filter(r => r.aeo_question)
  .slice(0, 10)
  .map(r => 'Q: ' + r.aeo_question + '\nA: ' + (r.aeo_short_answer || '').substring(0, 100))
  .join('\n---\n');

const totalBlocks = rows.reduce((s, r) => s + (r.total_blocks || 0), 0);
const totalWords = rows.reduce((s, r) => s + (r.total_word_count || 0), 0);
const avgScore = rows.length > 0 ? Math.round(rows.reduce((s, r) => s + (r.priority_score || 0), 0) / rows.length) : 0;

const nicheText = [
  'Ниша: ' + validate.niche,
  'Город: ' + validate.city,
  'Структур: ' + rows.length,
  'Блоков: ' + totalBlocks,
  'Слов: ' + totalWords,
  'Средний приоритет: ' + avgScore,
  'Типы: ' + JSON.stringify(typeBreakdown),
  '',
  'Топ структуры:',
  topStructures,
  '',
  'AEO:',
  aeoSummary
].join('\n');

return [{ json: {
  project_id: validate.project_id,
  niche: validate.niche,
  city: validate.city,
  niche_text: nicheText,
  structures_count: rows.length,
  total_blocks: totalBlocks,
  total_words: totalWords,
  avg_priority: avgScore,
  type_breakdown: typeBreakdown,
  rows
}}];

const prev = $('Prepare Qdrant Summary').first().json;
const vector = $input.first().json.embedding;
if (!vector || vector.length < 100) throw new Error('Invalid embedding: length=' + (vector?.length || 0));

// Deterministic UUID-like ID from project_id (more collision-resistant)
function stableHash(str) {
  let h1 = 0xdeadbeef, h2 = 0x41c6ce57;
  for (let i = 0; i < str.length; i++) {
    const ch = str.charCodeAt(i);
    h1 = Math.imul(h1 ^ ch, 2654435761);
    h2 = Math.imul(h2 ^ ch, 1597334677);
  }
  h1 = Math.imul(h1 ^ (h1 >>> 16), 2246822507) ^ Math.imul(h2 ^ (h2 >>> 13), 3266489909);
  h2 = Math.imul(h2 ^ (h2 >>> 16), 2246822507) ^ Math.imul(h1 ^ (h1 >>> 13), 3266489909);
  return (4294967296 * (2097151 & h2) + (h1 >>> 0)) % 2147483647;
}

const pointId = stableHash(prev.project_id + '_page_struct_v4');

return [{ json: { qdrant_payload: JSON.stringify({
  points: [{
    id: pointId,
    vector,
    payload: {
      project_id: prev.project_id,
      niche: prev.niche,
      city: prev.city,
      type: 'page_structure_analysis',
      structures_count: prev.structures_count,
      total_blocks: prev.total_blocks,
      total_words: prev.total_words,
      avg_priority: prev.avg_priority,
      type_breakdown: prev.type_breakdown,
      version: 'v4.0',
      created_at: new Date().toISOString()
    }
  }]
})}}];

const summary = $('Prepare Qdrant Summary').first().json;
const ragInfo = $('Format RAG Context').first().json;
const validate = $('Validate Input').first().json;
const rows = summary.rows || [];

const aeoCount = rows.filter(r => r.aeo_question).length;
let schemaCount = 0, ctaCount = 0, engineBoth = 0, engineYa = 0, engineG = 0;
rows.forEach(r => {
  try {
    const bl = typeof r.blocks === 'string' ? JSON.parse(r.blocks) : (r.blocks || []);
    schemaCount += bl.filter(b => b.schema_type && b.schema_type !== 'null').length;
    ctaCount += bl.filter(b => b.conversion_element && b.conversion_element !== 'null').length;
    bl.forEach(b => {
      if (b.engine_relevance === 'yandex') engineYa++;
      else if (b.engine_relevance === 'google') engineG++;
      else engineBoth++;
    });
  } catch(e) {}
});

// ML result
let mlScore = null, mlLabel = null;
try {
  const ml = $('ML Structure Predict').first().json;
  mlScore = ml.score ?? ml.prediction ?? null;
  mlLabel = ml.label ?? null;
} catch(e) {}

// Save statuses
let nocodbOk = false, qdrantOk = false;
try { const n = $('Save to NocoDB').first().json; nocodbOk = Array.isArray(n) || n?.Id != null; } catch(e) {}
try { const q = $('Save to Qdrant').first().json; qdrantOk = q?.result?.status === 'acknowledged' || q?.status === 'ok'; } catch(e) {}

const duration = Math.round((Date.now() - new Date(validate.started_at).getTime()) / 1000);

return [{ json: {
  status: 'success',
  step: '04_page_structure',
  version: 'v4.0_pro',
  project_id: summary.project_id,
  niche: summary.niche,
  city: summary.city,
  niche_cluster: validate.niche_cluster,
  priority_engines: validate.priority_engines,
  metrics: {
    structures_count: summary.structures_count,
    total_blocks: summary.total_blocks,
    total_word_count: summary.total_words,
    avg_priority_score: summary.avg_priority,
    aeo_blocks: aeoCount,
    schema_blocks: schemaCount,
    cta_blocks: ctaCount,
    type_breakdown: summary.type_breakdown,
    engine_tagging: { yandex: engineYa, google: engineG, both: engineBoth }
  },
  rag: {
    struct_sources: ragInfo.rag_struct_count,
    persona_sources: ragInfo.rag_persona_count,
    avg_relevance: ragInfo.rag_avg_score
  },
  ml: {
    structure_score: mlScore,
    structure_label: mlLabel,
    available: mlScore != null
  },
  storage: {
    qdrant_saved: qdrantOk,
    nocodb_saved: nocodbOk
  },
  execution: {
    duration_seconds: duration,
    timestamp: new Date().toISOString()
  }
}}];

const error = $input.first().json;
const errorResponse = {
  status: 'error',
  step: '04_page_structure',
  version: 'v4.0_pro',
  error: {
    message: error.message || error.error?.message || 'Unknown error',
    node: error.node?.name || 'unknown',
    timestamp: new Date().toISOString()
  }
};
return [{ json: errorResponse }];
